use std::fs;
use std::io;

fn read_file_with_retries(path: &str, max_retries: u32) -> io::Result<String> {
    let mut last_error = None;

    for attempt in 0..=max_retries {
        match fs::read_to_string(path) {
            Ok(content) => {
                println!("Successfully read file on attempt {}", attempt + 1);
                return Ok(content);
            }
            Err(e) => {
                println!("Attempt {} failed: {}", attempt + 1, e);
                last_error = Some(e);
            }
        }
    }

    // All retries exhausted
    Err(last_error.unwrap())
}

